import React, { useState, useEffect } from "react";
import "../assets/css/nav.css";

export default function Navbar() {
  const [menuData, setMenuData] = useState({ logo: "Moje Logo", menu: [] }); // Stan do przechowywania danych z pliku JSON

  useEffect(() => {
    // Ładowanie pliku JSON po załadowaniu komponentu
    fetch("/core/conf/nav/config.json")  // Sprawdź, czy plik JSON jest w folderze public/core/config
      .then(response => {
        if (!response.ok) {
          throw new Error("Błąd ładowania pliku JSON");
        }
        return response.json();  // Parsowanie odpowiedzi na JSON
      })
      .then(data => {
        setMenuData(data);  // Aktualizacja stanu z załadowanymi danymi
      })
      .catch(error => {
        console.error("Błąd ładowania danych:", error);
      });
  }, []);  // Używamy pustej tablicy, żeby wywołać efekt tylko raz, po pierwszym renderowaniu

  return (
    <nav className="nav">
      <div className="logo">{menuData.logo}</div>
      <ul className="menu">
        {menuData.menu.length > 0 ? (
          menuData.menu.map((item, index) => (
            <li key={index}>
              <a href={item.href}>{item.text}</a>
            </li>
          ))
        ) : (
          <p>Ładowanie menu...</p>
        )}
      </ul>
      <div className="burger">
        <div className="line"></div>
        <div className="line"></div>
        <div className="line"></div>
      </div>
    </nav>
  );
}
